var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"물론이죠. 출연하고 말고요!","JPN":"もちろんです。出演します！","ENG":"Of course. Of course I will be on!","TWN":"一定要的，我當然要演！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"네, 감사합니다! 내일 뵙겠습니다!","JPN":"はい、ありがとうございます！　明日お伺いします！","ENG":"Yes, thank you! See you tomorrow!","TWN":"是，謝謝！明天見！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"…음?","JPN":"……あれ？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"방금 뒤에서 무슨 소리가…?","JPN":"今、後ろから何か音が……？","ENG":"I think I heard something...?","TWN":"剛剛後面好像有什麼聲音…？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"잠시 실례하겠습니다, 아가씨.","JPN":"ちょっと失礼いたします、お嬢様。","ENG":"Excuse me for a moment, miss.","TWN":"抱歉囉，小姐。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！！","ENG":"Kyaaak!!","TWN":"啊啊啊！！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이게 어떻게 된 거지?","JPN":"いったいどうなってるんだ？","ENG":"What’s going on?","TWN":"這是怎麼回事？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"파벨라를 연기할 배우가 한 명 밖에 안 나왔다고? 그게 말이 돼?","JPN":"ファヴェーラを演じる女優が1人しか来なかっただと？　そんなことあり得るか？","ENG":"There's only one actress to play Fabella? That makes no sense!","TWN":"只有一個演員來試鏡帕貝拉的角色？這怎麼可能？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그것도 전원이 리허설 바로 전날에?!","JPN":"それも全員リハーサルの前日に！？","ENG":"And... they’re all not here on the day before the rehearsal?!","TWN":"而且還是在排演前一天？！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그러게요.","JPN":"そうですよね。","ENG":"Tell me about it.","TWN":"就是說嘛～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이 정도면 자격을 떠나서 배우로서 기본이 안된 거 아닌가?","JPN":"これだと資格はともかく、女優として基本がなってないのではないですか？","ENG":"Regardless of the qualifications, the rest don’t even have the basics as an actor.","TWN":"這樣根本連當演員的資格都沒有嘛～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"끄응…","JPN":"ぐぬぬ……","ENG":"Well...","TWN":"嗯…"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"뭐, 그래도 한 사람은 왔으니 최악은 면했군.","JPN":"まあ、それでも1人は来たし、最悪な事態は免れたな。","ENG":"At least one person is here, so the worst is behind us.","TWN":"起碼有來一個，還不到最慘的情況。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그럼 잘 부탁드려요, 감독님.","JPN":"それじゃあ、よろしくお願いします、監督。","ENG":"I won't let you down, Mr. Director.","TWN":"那就請多多指教囉，導演。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"으흠, 정말로 하루만에 다른 후보들이 코빼기조차 비치지 않다니.","JPN":"ふむ、本当にたったの一日で他の候補がまったく現われなくなるとは。","ENG":"Mm-hmm, it took only a day for the other candidates to not show up.","TWN":"嗯哼，竟然真的一天之內就擺平其他競爭對手，"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"제법이구나, 시종.","JPN":"やるではないか、僕。","ENG":"You did a good job, servant.","TWN":"有兩下子喔，僕人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"별 말씀을. 인간이라면 다들 하나씩 있는 약점을 이용해 처리했을 뿐이랍니다.","JPN":"とんでもありません。人間なら皆1つは持っている弱点を利用して処理しただけです。","ENG":"No need to say that. I just used the weakness that humans all have to take care of them.","TWN":"不敢不敢，我只是利用人類的弱點來解決他們而已。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"저기. 그런데 난 언제까지 여기서 이러고 가만히 서있어야 해?","JPN":"なあ、ところでアタシはいつまでここにじっと立ってないとダメなんだ？","ENG":"Excuse me? For how long am I supposed to stand here like this?","TWN":"我說，我要在這裡站到什麼時候？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네 녀석을 혼자 두고 왔다간 집에 있는 소파를 다 뜯어먹을 것 같아서 말이다.","JPN":"貴様を1人にしていたら、家中のソファを全部噛みちぎられそうでな。","ENG":"I figured you would chew up the whole sofa if I left you alone.","TWN":"我怕你自己在家的話，等回到家之後可能所有的沙發都會報銷。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`)